const nombre = $json.nombre_producto.toLowerCase();

const basura = [
  "original",
  "talle"
];

let limpio = nombre;

for (const palabra of basura) {
  const regex = new RegExp("\\b" + palabra + "\\b", "gi");
  limpio = limpio.replace(regex, "");
}

// quitar talles
limpio = limpio.replace(/\b(xs|s|m|l|xl|xxl)\b/gi, "");

// normalizar colores/género
limpio = limpio.replace(/\bnegra\b/g, "negro");
limpio = limpio.replace(/\bblanca\b/g, "blanco");
limpio = limpio.replace(/\broja\b/g, "rojo");
limpio = limpio.replace(/\bazul marino\b/g, "azul");

// limpiar espacios
limpio = limpio.replace(/\s+/g, " ").trim();

// eliminar palabras repetidas manteniendo orden
const palabras = limpio.split(" ");
const unicas = [];
for (const p of palabras) {
  if (!unicas.includes(p)) unicas.push(p);
}
limpio = unicas.join(" ");

return [{
  json: {
    ...$json,
    nombre_busqueda: limpio
  }
}];

const original = ($json.nombre_producto || "").toLowerCase();

let texto = original
  .normalize("NFD")
  .replace(/[\u0300-\u036f]/g, "");

// palabras que casi nunca ayudan
const basura = [
  "original",
  "talle",
  "usado",
  "usada",
  "nuevo",
  "nueva",
  "unidad",
  "unidades"
];

for (const palabra of basura) {
  texto = texto.replace(new RegExp("\\b" + palabra + "\\b", "gi"), "");
}

// quitar talles sueltos
texto = texto.replace(/\b(xs|s|m|l|xl|xxl|xxxl)\b/gi, "");

// normalizar género/color
texto = texto.replace(/\bnegra\b/g, "negro");
texto = texto.replace(/\bblanca\b/g, "blanco");
texto = texto.replace(/\broja\b/g, "rojo");

// quitar años y números largos
texto = texto.replace(/\b(19\d{2}|20\d{2})\b/g, "");
texto = texto.replace(/\b\d{3,}\b/g, "");

// limpiar símbolos
texto = texto.replace(/[^\w\s]/g, " ");
texto = texto.replace(/\s+/g, " ").trim();

// eliminar palabras repetidas manteniendo orden
let palabras = texto.split(" ").filter(Boolean);
const unicas = [];

for (const p of palabras) {
  if (!unicas.includes(p)) unicas.push(p);
}

palabras = unicas;

// búsqueda completa limpia
const nombre_busqueda = palabras.join(" ");

// palabras poco confiables para búsqueda corta
const secundarios = [
  "azul",
  "negro",
  "blanco",
  "gris",
  "rojo",
  "verde",
  "beige",
  "marron",
  "dorado",
  "plateado"
];

// búsqueda simple: saca colores y datos variables
const simples = palabras.filter(p => !secundarios.includes(p));
const nombre_busqueda_simple = simples.join(" ");

// búsquedas escalonadas desde más específica a más amplia
const busquedas = [];

function agregar(valor, permitirUnaPalabra = false) {
  valor = (valor || "").replace(/\s+/g, " ").trim();

  const cantidadPalabras = valor.split(" ").filter(Boolean).length;

  if (
    valor &&
    (cantidadPalabras >= 2 || permitirUnaPalabra) &&
    !busquedas.includes(valor)
  ) {
    busquedas.push(valor);
  }
}

agregar(nombre_busqueda);
agregar(nombre_busqueda_simple);

// recorte progresivo desde el final, mínimo 2 palabras
for (let i = palabras.length; i >= 2; i--) {
  agregar(palabras.slice(0, i).join(" "));
}

// recorte progresivo de la versión simple, mínimo 2 palabras
for (let i = simples.length; i >= 2; i--) {
  agregar(simples.slice(0, i).join(" "));
}

// último rescate: primera palabra del producto
// ejemplo: "aleron"
if (palabras[0]) {
  agregar(palabras[0], true);
}

return [{
  json: {
    ...$json,
    nombre_busqueda,
    nombre_busqueda_simple,
    busquedas,
    primera_busqueda: busquedas[0] || "",
    segunda_busqueda: busquedas[1] || "",
    tercera_busqueda: busquedas[2] || "",
    cuarta_busqueda: busquedas[3] || "",
    quinta_busqueda: busquedas[4] || ""
  }
}];

