const raw = $json.output || $json.text || $json.response || "";

let limpio = raw
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

const match = limpio.match(/\{[\s\S]*\}/);

if (!match) {
  return [{
    json: {
      id: "NO_MATCH",
      name: "",
      confidence: "",
      error: "La IA no devolvió JSON válido",
      raw
    }
  }];
}

let data;

try {
  data = JSON.parse(match[0]);
} catch (e) {
  return [{
    json: {
      id: "NO_MATCH",
      name: "",
      confidence: "",
      error: "No se pudo parsear JSON",
      raw
    }
  }];
}

return [{
  json: {
    id: data.id || "NO_MATCH",
    name: data.name || "",
    confidence: data.confidence || "",
    fuente: "IA"
  }
}];

